AND t.deleted = 0

    AND t.contract_no = #{contractNo}


    AND t.contract_name LIKE CONCAT('%', #{contractName}, '%')


    AND t.status = #{status}


    AND t.contract_direction = #{contractDirection}


    AND t.supplier_id = #{supplierId}


    AND t.manager_id = #{managerId}


    AND t.dept_id = #{deptId}

